import React from 'react';
import Trade from './Trade';

function TradeList(props) {
    const goodTrades = props.tradeList.filter(item => {
        return item.profitLoss>0
    })
    console.log('Good Trades = '+{goodTrades})
    
    return(
        <div>
            <table>
                <tbody>
                    <tr>
                        <td>ID</td>
                        <td>Stock</td>
                        <td>Method</td>
                        <td>Quantity</td>
                        <td>P/L</td>
                        <td className='td-blank'></td>
                    </tr>
                </tbody>
                
            </table>
            { props.tradeList.map(trade => {
                return <Trade key={trade.id} trade={trade} deleteHandler={props.deleteHandler} />
            }) }       
        </div>
    )
}

export default TradeList;
